import glob, re
from collections import defaultdict

def extract(html):
    out = []
    for row in re.findall(r'<tr[^>]*>(.*?)</tr>', html, re.S):
        cells = [re.sub(r'<[^>]+>', '', c).strip() for c in re.findall(r'<td[^>]*>(.*?)</td>', row, re.S)]
        for i, cell in enumerate(cells):
            m = re.fullmatch(r'(\d+)-(\d+)', cell)
            if m and 0 < i < len(cells)-1 and cells[i-1] and cells[i+1]:
                out.append((cells[i-1], int(m.group(1)), cells[i+1], int(m.group(2))))
                break
    return out

stats = defaultdict(lambda: dict(p=0,w=0,d=0,l=0,gf=0,ga=0,pts=0))
n = 0
for path in sorted(glob.glob('data/raw/statto-results-*.html')):
    date = re.search(r'(\d{4}-\d{2}-\d{2})', path).group(1)
    if date > '1974-09-07':
        continue
    for h, hs, a, asc in extract(open(path, encoding='utf-8', errors='replace').read()):
        n += 1
        for team, gf, ga in ((h, hs, asc), (a, asc, hs)):
            s = stats[team]; s['p'] += 1; s['gf'] += gf; s['ga'] += ga
            if gf > ga: s['w'] += 1; s['pts'] += 2
            elif gf == ga: s['d'] += 1; s['pts'] += 1
            else: s['l'] += 1

html = open('data/raw/11v11-table-1974-09-07.html', encoding='utf-8', errors='replace').read()
ALIASES = {'Wolverhampton Wanderers': 'Wolverhampton Wndrs', 'Queen\'s Park Rangers': 'Queens Park Rangers'}
ref = {}
for row in re.findall(r'<tr[^>]*>(.*?)</tr>', html, re.S):
    cells = [re.sub(r'<[^>]+>', '', c).strip() for c in re.findall(r'<td[^>]*>(.*?)</td>', row, re.S)]
    if len(cells) == 11 and cells[2].isdigit():
        team = ALIASES.get(cells[1], cells[1])
        ref[team] = dict(p=int(cells[2]), w=int(cells[3]), d=int(cells[4]), l=int(cells[5]),
                         gf=int(cells[6]), ga=int(cells[7]), pts=int(cells[10]))

print(f'CSV prefix matches <= 1974-09-07: {n}; 11v11 rows: {len(ref)}')
disc = 0
for team in sorted(set(ref) | set(stats)):
    if team not in ref: print(f'  DISCREPANCY: {team} only in CSV'); disc += 1; continue
    if team not in stats: print(f'  DISCREPANCY: {team} only in 11v11'); disc += 1; continue
    for k in ('p','w','d','l','gf','ga','pts'):
        if ref[team][k] != stats[team][k]:
            print(f'  DISCREPANCY: {team} {k.upper()}: CSV={stats[team][k]} 11v11={ref[team][k]}'); disc += 1
print('RESULT:', 'exact match for all teams, all 7 columns' if disc == 0 else f'{disc} discrepancies')
EOF

